mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY abp.reg_dttm DESC) rnum , abp.post_no postNo , abp.board_no boardNo , abp.ttl ttl , abp.cn cn , abp.wrtr_id wrtrId , wm.user_nm wrtrNm , abp.prrt_cd prrtCd , abp.reg_dttm regDttm , abp.mdf_dttm mdfDttm , abp.inq_cnt inqCnt , abp.del_yn delYn , abp.atch_file_id atchFileId , abp.opn_yn opnYn , abi.apt_cmplex_no aptCmplexNo , abi.board_ty_cd boardTyCd , abi.board_nm boardNm , CASE WHEN ans.cmt_no IS NULL THEN 'N' ELSE 'Y' END ansYn , ans.cmt_no ansCmtNo , ans.cmt_cn ansCn , ans.reg_dttm ansRegDttm , ans.mdf_dttm ansMdfDttm , ans.user_no ansUserNo , ans.user_nm ansUserNm FROM apt_board_post abp JOIN apt_board_instance abi ON abp.board_no = abi.board_no LEFT JOIN member wm ON wm.user_id = abp.wrtr_id
WHERE abi.board_ty_cd = #{boardTyCd} AND abi.use_yn = 'Y' AND abp.del_yn = 'N'
AND abi.apt_cmplex_no = #{aptCmplexNo}
AND abp.wrtr_id = #{wrtrId}
) WHERE rnum BETWEEN #{startRow} AND #{endRow}

mapper.insert:
INSERT INTO apt_board_post (
                             post_no
                           , board_no
                           , ttl
                           , cn
                           , wrtr_id
                           , prrt_cd
                           , reg_dttm
                           , mdf_dttm
                           , inq_cnt
                           , del_yn
                           , atch_file_id
                           , opn_yn
) VALUES (
           'IQ' || TO_CHAR(SYSDATE, 'YYMMDDHH24MISS')
         , #{boardNo}
         , #{ttl}
         , #{cn}
         , #{wrtrId}
         , #{prrtCd}
         , SYSDATE
         , NULL
         , 0
         , 'N'
         , #{atchFileId}
         , #{opnYn}
         )

mapper.update:
UPDATE apt_board_post abp
SET abp.del_yn = 'Y'
  , abp.mdf_dttm = SYSDATE
WHERE abp.post_no = #{postNo}
  AND abp.wrtr_id = #{wrtrId}
  AND EXISTS (
    SELECT 1
    FROM apt_board_instance abi
    WHERE abi.board_no = abp.board_no
      AND abi.apt_cmplex_no = #{aptCmplexNo}
      AND abi.board_ty_cd = #{boardTyCd}
      AND abi.use_yn = 'Y'
)

mapper.select:
SELECT COUNT(*)
FROM apt_board_post abp
         JOIN apt_board_instance abi
              ON abp.board_no = abi.board_no
WHERE abi.board_ty_cd = #{boardTyCd}
AND abi.use_yn = 'Y'
AND abp.del_yn = 'N'


    AND abi.apt_cmplex_no = #{aptCmplexNo}



    AND abp.wrtr_id = #{wrtrId}

mapper.insert:

    SELECT seq_board_comment.nextval FROM dual

INSERT INTO apt_board_comment (
    cmt_no
   ,post_no
   ,cmt_group
   ,cmt_cn
   ,cmt_sort_ord
   ,reg_dttm
   ,mdf_dttm
   ,del_yn
   ,user_no
) VALUES (
    #{ansCmtNo}
   ,#{postNo}
   ,#{ansCmtNo}
   ,#{ansCn}
   ,0
   ,SYSDATE
   ,SYSDATE
   ,'N'
   ,#{ansUserNo}
)

mapper.update:
UPDATE apt_board_comment
SET cmt_cn = #{cmtCn}
  , mdf_dttm = SYSDATE
  , user_no = #{userNo}
WHERE cmt_no = #{cmtNo}
  AND del_yn = 'N'

UPDATE apt_board_post
SET ttl       = #{dto.ttl}
  , cn        = #{dto.cn}
  , prrt_cd   = #{dto.prrtCd}
  , opn_yn    = #{dto.opnYn}
  , mdf_dttm  = SYSDATE
WHERE post_no   = #{dto.postNo}
  AND wrtr_id   = #{userId}
  AND del_yn    = 'N'
